import { DEFAULT_BREATHING_PERIOD } from '../AudioConfig';

export const WORKLET_WASM_PROCESSOR_NAME = 'bsc-worklet-wasm-session';

const BSC_DSP_WASM_BASE64 =
  '';

export function getWorkletWasmProcessorSource() {
  return `
const WASM_BASE64 = '${BSC_DSP_WASM_BASE64}';
const FRAME_SNAPSHOT_INTERVAL = 1024;
const SILENCE_GAIN = 0.00000001;
const CENTER_GAIN = Math.SQRT1_2;
const TWO_PI = Math.PI * 2;
const WASI_IMPORTS = {
  wasi_snapshot_preview1: {
    fd_close: () => 0,
    fd_seek: () => 0,
    fd_write: () => 0,
  },
};

const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
const dbToLinear = (db) => (db <= -100 ? 0 : Math.pow(10, db / 20));
const wrap01 = (value) => value - Math.floor(value);

const BASE64_ALPHABET = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
const BASE64_LOOKUP = new Uint8Array(256);
for (let i = 0; i < BASE64_ALPHABET.length; i += 1) {
  BASE64_LOOKUP[BASE64_ALPHABET.charCodeAt(i)] = i;
}

function decodeWasmBase64(base64) {
  let padding = 0;
  if (base64.charCodeAt(base64.length - 1) === 61) padding += 1;
  if (base64.charCodeAt(base64.length - 2) === 61) padding += 1;
  const byteLength = (base64.length * 3) / 4 - padding;
  const bytes = new Uint8Array(byteLength);
  let byteIndex = 0;
  for (let i = 0; i < base64.length; i += 4) {
    const c0 = BASE64_LOOKUP[base64.charCodeAt(i)];
    const c1 = BASE64_LOOKUP[base64.charCodeAt(i + 1)];
    const c2 = BASE64_LOOKUP[base64.charCodeAt(i + 2)];
    const c3 = BASE64_LOOKUP[base64.charCodeAt(i + 3)];
    bytes[byteIndex] = (c0 << 2) | (c1 >> 4);
    if (byteIndex + 1 < byteLength) bytes[byteIndex + 1] = ((c1 & 15) << 4) | (c2 >> 2);
    if (byteIndex + 2 < byteLength) bytes[byteIndex + 2] = ((c2 & 3) << 6) | c3;
    byteIndex += 3;
  }
  return bytes;
}

function jsWave(phase, waveform) {
  const p = wrap01(phase);
  if (waveform === 1) return 4 * Math.abs(p - 0.5) - 1;
  if (waveform === 2) return p < 0.5 ? 1 : -1;
  if (waveform === 3) return 2 * p - 1;
  return Math.sin(TWO_PI * p);
}

function computeAdaptiveEnvelope(noteSep) {
  const BASE_A = 0.02;
  const BASE_D = 0.1;
  const BASE_S = 0.8;
  const BASE_R = 0.05;
  const MIN_D = 0.02;
  const MIN_R = 0.02;
  const MIN_RAMP = 0.01;

  if (noteSep > 10) {
    const noteDur = noteSep / 2;
    const rel = Math.min(1, noteDur);
    return { attack: 2, decay: 2, sustain: 1, release: rel, soundDur: noteDur + rel };
  }
  if (noteSep >= 2 * (BASE_A + BASE_D)) {
    const noteDur = noteSep / 2;
    const rel = Math.min(BASE_R, noteSep - noteDur);
    return { attack: BASE_A, decay: BASE_D, sustain: BASE_S, release: rel, soundDur: noteDur + rel };
  }
  if (noteSep >= BASE_A + BASE_D + BASE_R) {
    return { attack: BASE_A, decay: BASE_D, sustain: BASE_S, release: BASE_R, soundDur: noteSep };
  }
  const availD = noteSep - BASE_A - BASE_R;
  if (availD >= MIN_D) {
    return { attack: BASE_A, decay: Math.min(BASE_D, availD), sustain: BASE_S, release: BASE_R, soundDur: noteSep };
  }
  if (noteSep >= BASE_A + BASE_R) {
    return { attack: BASE_A, decay: 0, sustain: 1, release: BASE_R, soundDur: noteSep };
  }
  const availR = noteSep - BASE_A;
  if (availR >= MIN_R) {
    return { attack: BASE_A, decay: 0, sustain: 1, release: availR, soundDur: noteSep };
  }
  const half = Math.max(MIN_RAMP, noteSep / 2);
  return { attack: half, decay: 0, sustain: 1, release: half, soundDur: noteSep };
}

function readEnvelope(env, timeInNote) {
  if (timeInNote < 0 || timeInNote > env.soundDur) return 0;
  if (env.attack > 0 && timeInNote < env.attack) {
    return timeInNote / env.attack;
  }
  const decayEnd = env.attack + env.decay;
  if (env.decay > 0 && timeInNote < decayEnd) {
    const progress = (timeInNote - env.attack) / env.decay;
    return 1 - (1 - env.sustain) * progress;
  }
  const releaseStart = Math.max(decayEnd, env.soundDur - env.release);
  if (timeInNote < releaseStart) return env.sustain;
  if (env.release <= 0) return 0;
  return env.sustain * (1 - (timeInNote - releaseStart) / env.release);
}

function makeVoice(raw) {
  const gain = dbToLinear(raw.gainDb ?? -100);
  return {
    ...raw,
    currentGain: 0,
    targetGain: gain,
    volumeGain: gain,
    gainStep: 0,
    gainFramesLeft: 0,
    phaseL: 0,
    phaseR: 0,
    phaseM: 0,
    noiseBrown: 0,
    noisePink: new Array(7).fill(0),
    noiseSourceColor: raw.noiseColor ?? 0,
    noiseTargetColor: raw.noiseColor ?? 0,
    noiseCrossfadeFramesLeft: 0,
    noiseCrossfadeTotalFrames: 0,
    symmetryPhases: new Array(raw.maxChordSize ?? 1).fill(0),
    symmetryEnv: raw.noteSep ? computeAdaptiveEnvelope(raw.noteSep) : null,
    _breathCache: null,
    _symmetryFreqs: null,
    _symmetryEnvValue: 0,
    _symmetryCrossesSlotBoundary: false,
    _wasmRendered: false,
    _sharedDspIndex: -1,
  };
}

function voiceUsesSharedDsp(voice) {
  return voice.type === 'Binaural' || voice.type === 'Martigli' || voice.type === 'Martigli-Binaural' || voice.type === 'Symmetry' || voice.type === 'Noise';
}

function voiceHasSharedBreath(voice) {
  return voice.type === 'Martigli' || voice.type === 'Martigli-Binaural';
}

function applyGainTarget(voice, gain, frames) {
  voice.targetGain = gain;
  voice.gainFramesLeft = Math.max(0, Math.floor(frames));
  if (voice.gainFramesLeft <= 0) {
    voice.currentGain = gain;
    voice.gainStep = 0;
  } else {
    voice.gainStep = (gain - voice.currentGain) / voice.gainFramesLeft;
  }
}

function updateGain(voice) {
  if (voice.gainFramesLeft > 0) {
    voice.currentGain += voice.gainStep;
    voice.gainFramesLeft -= 1;
    if (voice.gainFramesLeft <= 0) {
      voice.currentGain = voice.targetGain;
      voice.gainStep = 0;
    }
  }
}

function readBreath(voice, elapsed) {
  const mp0 = Math.max(0.1, voice.mp0 ?? ${DEFAULT_BREATHING_PERIOD});
  const mp1 = Math.max(0.1, voice.mp1 ?? mp0);
  const md = Math.max(0, voice.md ?? 0);
  const ratio = clamp(voice.inhaleRatio ?? 0.5, 0.05, 0.95);
  const rampProgress = md > 0 ? clamp(elapsed / md, 0, 1) : 1;
  const period = Math.max(0.1, mp0 + (mp1 - mp0) * rampProgress);
  const phase = wrap01(elapsed / period);
  const inhale = phase < ratio;
  const segmentPhase = inhale
    ? phase / ratio
    : (phase - ratio) / Math.max(1 - ratio, 0.0001);
  const signed = inhale
    ? -Math.cos(Math.PI * segmentPhase)
    : Math.cos(Math.PI * segmentPhase);
  const breathValue01 = (signed + 1) / 2;

  return {
    signed,
    breathValue01,
    cyclePhase01: phase,
    direction: inhale ? 1 : 0,
    inhaleRatio: ratio,
    actualRatio: ratio,
    currentPeriod: period,
    targetPeriod: mp1,
    mp0,
    mp1,
  };
}

function readHoldCrossfadePanSwap(voice, elapsed) {
  const period = Math.max(0.001, voice.panOscPeriod ?? 120);
  const transition = clamp(voice.panOscTrans ?? 20, 0, period);
  const cycle = period * 2;
  const phase = ((elapsed % cycle) + cycle) % cycle;

  if (transition <= 0) {
    return phase < period ? 0 : 1;
  }

  const firstHoldEnd = period - transition;
  if (phase < firstHoldEnd) return 0;
  if (phase < period) {
    return clamp((phase - firstHoldEnd) / transition, 0, 1);
  }

  const secondHoldEnd = cycle - transition;
  if (phase < secondHoldEnd) return 1;
  return clamp(1 - (phase - secondHoldEnd) / transition, 0, 1);
}

function readPanSwap(voice, elapsed, syncedBreath) {
  if (voice.panOsc === 1) {
    return readHoldCrossfadePanSwap(voice, elapsed);
  }
  if (voice.panOsc === 2 && (voice.panOscPeriod ?? 0) > 0) {
    return clamp((Math.sin(TWO_PI * elapsed / voice.panOscPeriod) + 1) / 2, 0, 1);
  }
  if (voice.panOsc === 3) {
    const breath = voice._breathCache ?? syncedBreath;
    if (!breath) return 0;
    const value = breath.breathValue01 ?? (
      breath.signed == null ? 0 : (breath.signed + 1) / 2
    );
    return Number.isFinite(value) ? clamp(value, 0, 1) : 0;
  }
  return 0;
}

function seededOrder(slotCount, cycle) {
  const order = Array.from({ length: slotCount }, (_, index) => index);
  let state = (cycle + 1) * 0x6d2b79f5;
  for (let index = order.length - 1; index > 0; index -= 1) {
    state = Math.imul(state ^ (state >>> 15), state | 1);
    const swapIndex = Math.abs(state) % (index + 1);
    const temp = order[index];
    order[index] = order[swapIndex];
    order[swapIndex] = temp;
  }
  return order;
}

function readSymmetrySlot(voice, elapsed) {
  const slots = voice.noteSlots ?? [[100]];
  const slotCount = Math.max(1, slots.length);
  const noteSep = Math.max(0.02, voice.noteSep ?? 1);
  const cycleSeconds = Math.max(noteSep, voice.cycleSeconds ?? noteSep * slotCount);
  const cycle = Math.floor(elapsed / cycleSeconds);
  const cyclePhase = elapsed - cycle * cycleSeconds;
  const slotIndex = clamp(Math.floor(cyclePhase / noteSep), 0, slotCount - 1);
  const timeInNote = cyclePhase - slotIndex * noteSep;
  const rows = voice.permutationRows;
  let sourceIndex = slotIndex;

  if (Array.isArray(rows) && rows.length > 0) {
    sourceIndex = rows[cycle % rows.length]?.[slotIndex] ?? slotIndex;
  } else if (voice.permfunc === 0) {
    sourceIndex = seededOrder(slotCount, cycle)[slotIndex] ?? slotIndex;
  } else if (voice.permfunc === 1) {
    sourceIndex = (slotIndex - ((cycle + 1) % slotCount) + slotCount) % slotCount;
  } else if (voice.permfunc === 2) {
    sourceIndex = (slotIndex + cycle + 1) % slotCount;
  } else if (voice.permfunc === 3 && cycle % 2 === 0) {
    sourceIndex = slotCount - slotIndex - 1;
  }

  return {
    frequencies: slots[sourceIndex] ?? slots[slotIndex] ?? [],
    timeInNote,
  };
}

function quantumCrossesSymmetrySlotBoundary(voice, timeInNote) {
  const noteSep = Math.max(0.02, voice.noteSep ?? 1);
  return timeInNote + QUANTUM_FRAMES / sampleRate > noteSep;
}

const QUANTUM_FRAMES = 128;
const HEALTH_REPORT_INTERVAL_SECONDS = 1;
const RENDER_BUDGET_EMA_ALPHA = 0.1;
const XRUN_GAP_FACTOR = 2;
const NOISE_COLOR_CROSSFADE_SECONDS = 0.3;
const hasPerfNow =
  typeof performance !== 'undefined' && typeof performance.now === 'function';
const readPerfNow = () => (hasPerfNow ? performance.now() : 0);

class BscWorkletWasmSessionProcessor extends AudioWorkletProcessor {
  constructor() {
    super();
    this.voices = [];
    this.elapsed = 0;
    this.state = 'idle';
    this.pauseFramesLeft = 0;
    this.stopFramesLeft = 0;
    this.framesSinceSnapshot = 0;
    this.wave = jsWave;
    this.wasmReady = false;
    this.port.onmessage = (event) => this.handleMessage(event.data ?? {});

    this.quantumDurationMs = (QUANTUM_FRAMES * 1000) / sampleRate;
    this.renderBudgetEma = 0;
    this.renderBudgetMaxPct = 0;
    this.possibleXrunCount = 0;
    this.processCallCount = 0;
    this.lastProcessEndPerfMs = 0;
    this.lastHealthReportAudioTime = 0;
    this.lastElapsedReportAudioTime = 0;
    this.fatalError = null;
    this._scrL = 0;
    this._scrR = 0;
    this._wasmInstance = null;
    this._wasmPhase = null;
    this._wasmOutL = null;
    this._wasmOutR = null;
    this._wasmSymmetryPhases = null;
    this._wasmSymmetryFreqs = null;
    this._sharedSymmetrySlotFreqs = null;
    this._sharedSymmetrySlotSizes = null;
    this._sharedSymmetryRows = null;
    this._sharedDspOutL = null;
    this._sharedDspOutR = null;
    this._sharedDspSnapshot = null;
    this._sharedDspRendered = false;
    this._sharedDspVoiceIndexes = [];
    this._voiceOutL = [];
    this._voiceOutR = [];
    this.syncedBreathCache = null;

    let wasmBytes = null;
    try {
      wasmBytes = decodeWasmBase64(WASM_BASE64);
    } catch (error) {
      this.fatalError = {
        stage: 'wasm-decode',
        message: error instanceof Error ? error.message : String(error),
      };
      this.port.postMessage({ type: 'error', ...this.fatalError });
      return;
    }

    try {
      WebAssembly.instantiate(wasmBytes, WASI_IMPORTS)
        .then((result) => {
          const wasmExports = result.instance.exports;
          if (typeof wasmExports.wave === 'function') {
            this.wave = wasmExports.wave;
          }
          this._wasmInstance = result.instance;
          if (wasmExports.memory) {
            const buffer = wasmExports.memory.buffer;
            this._wasmPhase = new Float64Array(buffer, wasmExports.bsc_phase_ptr(), 32);
            this._wasmOutL = new Float64Array(buffer, wasmExports.bsc_out_l_ptr(), 128);
            this._wasmOutR = new Float64Array(buffer, wasmExports.bsc_out_r_ptr(), 128);
            this._wasmSymmetryPhases = new Float64Array(
              buffer,
              wasmExports.bsc_symmetry_phases_ptr(),
              32,
            );
            this._wasmSymmetryFreqs = new Float64Array(
              buffer,
              wasmExports.bsc_symmetry_freqs_ptr(),
              32,
            );
            if (
              typeof wasmExports.bsc_symmetry_slot_freqs_ptr === 'function' &&
              typeof wasmExports.bsc_symmetry_slot_sizes_ptr === 'function' &&
              typeof wasmExports.bsc_symmetry_rows_ptr === 'function'
            ) {
              this._sharedSymmetrySlotFreqs = new Float64Array(
                buffer,
                wasmExports.bsc_symmetry_slot_freqs_ptr(),
                32 * 32,
              );
              this._sharedSymmetrySlotSizes = new Int32Array(
                buffer,
                wasmExports.bsc_symmetry_slot_sizes_ptr(),
                32,
              );
              this._sharedSymmetryRows = new Int32Array(
                buffer,
                wasmExports.bsc_symmetry_rows_ptr(),
                32 * 32,
              );
            }
            this._sharedDspOutL = new Float32Array(
              buffer,
              wasmExports.bsc_session_out_l_ptr(),
              128,
            );
            this._sharedDspOutR = new Float32Array(
              buffer,
              wasmExports.bsc_session_out_r_ptr(),
              128,
            );
            this._sharedDspSnapshot = new Float64Array(
              buffer,
              wasmExports.bsc_session_snapshot_ptr(),
              10,
            );
          }
          if (this.voices.length > 0) {
            this.configureSharedDspSession(this.elapsed);
          }
          this.wasmReady = true;
          this.port.postMessage({ type: 'ready', wasmReady: true });
        })
        .catch((error) => {
          this.fatalError = {
            stage: 'wasm-instantiate',
            message: error instanceof Error ? error.message : String(error),
          };
          this.port.postMessage({ type: 'error', ...this.fatalError });
        });
    } catch (error) {
      this.fatalError = {
        stage: 'wasm-instantiate',
        message: error instanceof Error ? error.message : String(error),
      };
      this.port.postMessage({ type: 'error', ...this.fatalError });
    }
  }

  writeSharedSymmetryConfig(voice) {
    if (
      !this._sharedSymmetrySlotFreqs ||
      !this._sharedSymmetrySlotSizes ||
      !this._sharedSymmetryRows
    ) {
      return null;
    }

    const slots = voice.noteSlots ?? [[100]];
    const slotCount = slots.length;
    const maxChordSize = Math.max(1, ...slots.map((slot) => slot.length));
    const rows = Array.isArray(voice.permutationRows) ? voice.permutationRows : [];
    if (
      slotCount <= 0 ||
      slotCount > 32 ||
      maxChordSize <= 0 ||
      maxChordSize > 32 ||
      rows.length > 32
    ) {
      return null;
    }

    this._sharedSymmetrySlotFreqs.fill(0);
    this._sharedSymmetrySlotSizes.fill(0);
    this._sharedSymmetryRows.fill(0);

    for (let slotIndex = 0; slotIndex < slotCount; slotIndex += 1) {
      const slot = slots[slotIndex] ?? [];
      if (!Array.isArray(slot) || slot.length <= 0 || slot.length > maxChordSize) {
        return null;
      }
      this._sharedSymmetrySlotSizes[slotIndex] = slot.length;
      for (let lane = 0; lane < slot.length; lane += 1) {
        if (!Number.isFinite(slot[lane]) || slot[lane] <= 0 || slot[lane] > 20000) {
          return null;
        }
        this._sharedSymmetrySlotFreqs[slotIndex * 32 + lane] = slot[lane];
      }
    }

    for (let rowIndex = 0; rowIndex < rows.length; rowIndex += 1) {
      const row = rows[rowIndex];
      if (!Array.isArray(row) || row.length !== slotCount) return null;
      for (let slotIndex = 0; slotIndex < slotCount; slotIndex += 1) {
        const sourceIndex = row[slotIndex];
        if (!Number.isInteger(sourceIndex) || sourceIndex < 0 || sourceIndex >= slotCount) {
          return null;
        }
        this._sharedSymmetryRows[rowIndex * 32 + slotIndex] = sourceIndex;
      }
    }

    return { slotCount, maxChordSize, rowCount: rows.length };
  }

  configureSharedDspSession(initialElapsed = this.elapsed) {
    const exports = this._wasmInstance?.exports;
    if (!exports?.bsc_session_clear) return;
    exports.bsc_session_clear();
    this._sharedDspVoiceIndexes = [];

    for (let vi = 0; vi < this.voices.length; vi += 1) {
      const voice = this.voices[vi];
      voice._sharedDspIndex = -1;
      if (!voiceUsesSharedDsp(voice)) continue;

      let sharedIndex = -1;
      if (voice.type === 'Binaural') {
        sharedIndex = exports.bsc_session_add_binaural(
          voice.isOn === false ? 0 : 1,
          voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
          voice.fl ?? 200,
          voice.fr ?? 210,
          voice.waveformL ?? 0,
          voice.waveformR ?? 0,
          voice.panOsc ?? 0,
          voice.panOscPeriod ?? 120,
          voice.panOscTrans ?? 20,
        );
      } else if (voice.type === 'Symmetry') {
        const symmetryConfig = this.writeSharedSymmetryConfig(voice);
        if (symmetryConfig && typeof exports.bsc_session_add_symmetry === 'function') {
          sharedIndex = exports.bsc_session_add_symmetry(
            voice.isOn === false ? 0 : 1,
            voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
            symmetryConfig.slotCount,
            symmetryConfig.maxChordSize,
            symmetryConfig.rowCount,
            voice.waveform ?? 0,
            voice.permfunc ?? 4,
            voice.noteSep ?? 1,
            voice.cycleSeconds ?? Math.max(1, symmetryConfig.slotCount),
          );
        }
      } else if (voice.type === 'Martigli') {
        sharedIndex = exports.bsc_session_add_martigli(
          voice.isOn === false ? 0 : 1,
          voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
          voice.mf0 ?? 250,
          voice.ma ?? 90,
          voice.mp0 ?? ${DEFAULT_BREATHING_PERIOD},
          voice.mp1 ?? voice.mp0 ?? ${DEFAULT_BREATHING_PERIOD},
          voice.md ?? 0,
          voice.inhaleRatio ?? 0.5,
          voice.waveformM ?? voice.waveform ?? 0,
          voice.martigliComfortGainEnabled === true ? 1 : 0,
          voice.martigliComfortLowDb ?? 0,
          voice.martigliComfortHighDb ?? 0,
          voice.panOsc ?? 0,
          voice.panOscPeriod ?? 120,
          voice.panOscTrans ?? 20,
        );
      } else if (voice.type === 'Martigli-Binaural') {
        sharedIndex = exports.bsc_session_add_martigli_binaural(
          voice.isOn === false ? 0 : 1,
          voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
          voice.fl ?? 250,
          voice.fr ?? 260,
          voice.ma ?? 90,
          voice.mp0 ?? ${DEFAULT_BREATHING_PERIOD},
          voice.mp1 ?? voice.mp0 ?? ${DEFAULT_BREATHING_PERIOD},
          voice.md ?? 0,
          voice.inhaleRatio ?? 0.5,
          voice.waveformL ?? 0,
          voice.waveformR ?? 0,
          voice.martigliComfortGainEnabled === true ? 1 : 0,
          voice.martigliComfortLowDb ?? 0,
          voice.martigliComfortHighDb ?? 0,
          voice.panOsc ?? 0,
          voice.panOscPeriod ?? 120,
          voice.panOscTrans ?? 20,
        );
      } else if (voice.type === 'Noise') {
        if (typeof exports.bsc_session_add_noise === 'function') {
          sharedIndex = exports.bsc_session_add_noise(
            voice.isOn === false ? 0 : 1,
            voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
            voice.noiseColor ?? 0,
          );
        }
      }

      if (sharedIndex >= 0) {
        voice._sharedDspIndex = sharedIndex;
        this._sharedDspVoiceIndexes[sharedIndex] = vi;
      }
    }

    exports.bsc_session_load(Math.max(0, initialElapsed));
    this.syncSharedDspTransport();
  }

  syncSharedDspTransport() {
    const exports = this._wasmInstance?.exports;
    if (!exports?.bsc_session_start) return;

    const initialElapsed = Math.max(0, this.elapsed);
    if (this.state === 'playing') {
      exports.bsc_session_start(initialElapsed, 0);
    } else if (this.state === 'pausing') {
      exports.bsc_session_start(initialElapsed, 0);
      exports.bsc_session_pause?.(Math.max(0, this.pauseFramesLeft) / sampleRate);
    } else if (this.state === 'stopping') {
      exports.bsc_session_start(initialElapsed, 0);
      exports.bsc_session_stop?.(Math.max(0, this.stopFramesLeft) / sampleRate);
    }
  }

  updateSharedDspVoice(voice) {
    const exports = this._wasmInstance?.exports;
    const sharedIndex = voice?._sharedDspIndex ?? -1;
    if (!exports || sharedIndex < 0) return;

    if (voice.type === 'Binaural') {
      exports.bsc_session_update_binaural(
        sharedIndex,
        voice.isOn === false ? 0 : 1,
        voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
        voice.fl ?? 200,
        voice.fr ?? 210,
        voice.waveformL ?? 0,
        voice.waveformR ?? 0,
        voice.panOsc ?? 0,
        voice.panOscPeriod ?? 120,
        voice.panOscTrans ?? 20,
      );
    } else if (voice.type === 'Symmetry') {
      const symmetryConfig = this.writeSharedSymmetryConfig(voice);
      if (symmetryConfig && typeof exports.bsc_session_update_symmetry === 'function') {
        exports.bsc_session_update_symmetry(
          sharedIndex,
          voice.isOn === false ? 0 : 1,
          voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
          symmetryConfig.slotCount,
          symmetryConfig.maxChordSize,
          symmetryConfig.rowCount,
          voice.waveform ?? 0,
          voice.permfunc ?? 4,
          voice.noteSep ?? 1,
          voice.cycleSeconds ?? Math.max(1, symmetryConfig.slotCount),
        );
      }
    } else if (voice.type === 'Martigli') {
      exports.bsc_session_update_martigli(
        sharedIndex,
        voice.isOn === false ? 0 : 1,
        voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
        voice.mf0 ?? 250,
        voice.ma ?? 90,
        voice.mp0 ?? ${DEFAULT_BREATHING_PERIOD},
        voice.mp1 ?? voice.mp0 ?? ${DEFAULT_BREATHING_PERIOD},
        voice.md ?? 0,
        voice.inhaleRatio ?? 0.5,
        voice.waveformM ?? voice.waveform ?? 0,
        voice.martigliComfortGainEnabled === true ? 1 : 0,
        voice.martigliComfortLowDb ?? 0,
        voice.martigliComfortHighDb ?? 0,
        voice.panOsc ?? 0,
        voice.panOscPeriod ?? 120,
        voice.panOscTrans ?? 20,
      );
    } else if (voice.type === 'Martigli-Binaural') {
      exports.bsc_session_update_martigli_binaural(
        sharedIndex,
        voice.isOn === false ? 0 : 1,
        voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
        voice.fl ?? 250,
        voice.fr ?? 260,
        voice.ma ?? 90,
        voice.mp0 ?? ${DEFAULT_BREATHING_PERIOD},
        voice.mp1 ?? voice.mp0 ?? ${DEFAULT_BREATHING_PERIOD},
        voice.md ?? 0,
        voice.inhaleRatio ?? 0.5,
        voice.waveformL ?? 0,
        voice.waveformR ?? 0,
        voice.martigliComfortGainEnabled === true ? 1 : 0,
        voice.martigliComfortLowDb ?? 0,
        voice.martigliComfortHighDb ?? 0,
        voice.panOsc ?? 0,
        voice.panOscPeriod ?? 120,
        voice.panOscTrans ?? 20,
      );
    } else if (voice.type === 'Noise') {
      if (typeof exports.bsc_session_update_noise === 'function') {
        exports.bsc_session_update_noise(
          sharedIndex,
          voice.isOn === false ? 0 : 1,
          voice.volumeGain ?? dbToLinear(voice.gainDb ?? -100),
          voice.noiseColor ?? 0,
        );
      }
    }
  }

  readSharedDspSnapshot(voice) {
    const exports = this._wasmInstance?.exports;
    const sharedIndex = voice?._sharedDspIndex ?? -1;
    if (!exports?.bsc_session_get_breath_snapshot || sharedIndex < 0) return null;
    if (exports.bsc_session_get_breath_snapshot(sharedIndex) !== 1) return null;
    return {
      audioTime: this._sharedDspSnapshot[0],
      cyclePhase01: this._sharedDspSnapshot[1],
      breathValue01: this._sharedDspSnapshot[2],
      direction: this._sharedDspSnapshot[3],
      inhaleRatio: this._sharedDspSnapshot[4],
      actualRatio: this._sharedDspSnapshot[5],
      currentPeriod: this._sharedDspSnapshot[6],
      targetPeriod: this._sharedDspSnapshot[7],
      mp0: this._sharedDspSnapshot[8],
      mp1: this._sharedDspSnapshot[9],
      signed: this._sharedDspSnapshot[2] * 2 - 1,
    };
  }

  handleMessage(message) {
    if (message.type === 'load') {
      this.voices = (message.voices ?? []).map(makeVoice);
      this.elapsed = Math.max(0, message.initialElapsed ?? 0);
      this.state = 'loaded';
      this._voiceOutL = this.voices.map(() => new Float64Array(128));
      this._voiceOutR = this.voices.map(() => new Float64Array(128));
      this.configureSharedDspSession(this.elapsed);
      return;
    }

    if (message.type === 'start') {
      this.elapsed = Math.max(0, message.initialElapsed ?? this.elapsed);
      this.state = 'playing';
      this.renderBudgetEma = 0;
      this.renderBudgetMaxPct = 0;
      this.possibleXrunCount = 0;
      this.processCallCount = 0;
      this.lastProcessEndPerfMs = 0;
      this.lastHealthReportAudioTime = currentTime;
      this.lastElapsedReportAudioTime = currentTime;
      const frames = Math.round((message.fadeMs ?? 2000) * sampleRate / 1000);
      this.voices.forEach((voice) => applyGainTarget(voice, voice.volumeGain, frames));
      this._wasmInstance?.exports?.bsc_session_start?.(
        this.elapsed,
        (message.fadeMs ?? 2000) / 1000,
      );
      return;
    }

    if (message.type === 'pause') {
      this.state = 'pausing';
      this.pauseFramesLeft = Math.round((message.fadeMs ?? 500) * sampleRate / 1000);
      this.voices.forEach((voice) => applyGainTarget(voice, 0, this.pauseFramesLeft));
      this._wasmInstance?.exports?.bsc_session_pause?.((message.fadeMs ?? 500) / 1000);
      return;
    }

    if (message.type === 'resume') {
      this.state = 'playing';
      const frames = Math.round((message.fadeMs ?? 500) * sampleRate / 1000);
      this.voices.forEach((voice) => applyGainTarget(voice, voice.volumeGain, frames));
      this._wasmInstance?.exports?.bsc_session_resume?.((message.fadeMs ?? 500) / 1000);
      return;
    }

    if (message.type === 'resetBreathing') {
      const index = message.index ?? 0;
      const voice = this.voices[index];
      if (
        voice &&
        voice._sharedDspIndex >= 0 &&
        this._wasmInstance?.exports?.bsc_session_reset_breathing?.(
          voice._sharedDspIndex,
        ) === 1
      ) {
        // Refresh the cached snapshot and publish it immediately so the visual
        // reads the empty-lungs boundary on resume instead of the stale
        // pre-pause phase before the next render-driven snapshot lands.
        const snapshot = this.readSharedDspSnapshot(voice);
        if (snapshot) {
          voice._breathCache = snapshot;
          this.port.postMessage({
            type: 'breathingSnapshot',
            index,
            snapshot: { ...snapshot, audioTime: currentTime },
          });
        }
      }
      return;
    }

    if (message.type === 'stop') {
      this.state = 'stopping';
      this.stopFramesLeft = Math.round((message.fadeMs ?? 2000) * sampleRate / 1000);
      this.voices.forEach((voice) => applyGainTarget(voice, 0, this.stopFramesLeft));
      this._wasmInstance?.exports?.bsc_session_stop?.((message.fadeMs ?? 2000) / 1000);
      return;
    }

    if (message.type === 'setVoiceVolume') {
      const voice = this.voices[message.index];
      if (!voice) return;
      voice.gainDb = message.gainDb;
      const nextGain = dbToLinear(message.gainDb);
      voice.volumeGain = nextGain;
      if (voice._sharedDspIndex >= 0) {
        this._wasmInstance?.exports?.bsc_session_set_voice_gain?.(
          voice._sharedDspIndex,
          nextGain,
          (message.fadeMs ?? 500) / 1000,
        );
      }
      applyGainTarget(
        voice,
        this.state === 'playing' ? nextGain : 0,
        Math.round((message.fadeMs ?? 500) * sampleRate / 1000),
      );
      return;
    }

    if (message.type === 'updateVoice') {
      const current = this.voices[message.index];
      if (!current) return;
      const noiseColorChanged =
        current.type === 'Noise' &&
        Number.isFinite(message.voice?.noiseColor) &&
        message.voice.noiseColor !== current.noiseColor;
      const next = makeVoice({ ...current, ...message.voice });
      next._sharedDspIndex = current._sharedDspIndex;
      next.currentGain = current.currentGain;
      next.gainStep = current.gainStep;
      next.gainFramesLeft = current.gainFramesLeft;
      next.volumeGain = dbToLinear(next.gainDb ?? current.gainDb ?? -100);
      if (next.gainFramesLeft <= 0) {
        next.targetGain = next.volumeGain;
        next.currentGain = this.state === 'playing' ? next.volumeGain : 0;
      } else {
        next.targetGain = current.targetGain;
      }
      next.phaseL = current.phaseL;
      next.phaseR = current.phaseR;
      next.phaseM = current.phaseM;
      next.noiseBrown = current.noiseBrown;
      next.noisePink = current.noisePink;
      if (noiseColorChanged) {
        next.noiseSourceColor = current.noiseColor ?? 0;
        next.noiseTargetColor = message.voice.noiseColor;
        next.noiseCrossfadeFramesLeft = Math.max(
          1,
          Math.round(NOISE_COLOR_CROSSFADE_SECONDS * sampleRate),
        );
        next.noiseCrossfadeTotalFrames = next.noiseCrossfadeFramesLeft;
      }
      next.symmetryPhases = current.symmetryPhases;
      this.voices[message.index] = next;
      if (voiceUsesSharedDsp(next) && next._sharedDspIndex >= 0) {
        this.updateSharedDspVoice(next);
      } else if (voiceUsesSharedDsp(current) !== voiceUsesSharedDsp(next)) {
        this.configureSharedDspSession(this.elapsed);
      }
    }
  }

  prepareQuantum() {
    const elapsed = this.elapsed;
    let syncedBreath = null;
    this._sharedDspRendered = false;
    for (let vi = 0; vi < this.voices.length; vi += 1) {
      const voice = this.voices[vi];
      voice._wasmRendered = false;
      if (voiceHasSharedBreath(voice)) {
        voice._breathCache =
          voice._sharedDspIndex >= 0
            ? this.readSharedDspSnapshot(voice) ?? readBreath(voice, elapsed)
            : readBreath(voice, elapsed);
        if (syncedBreath === null && voice.isOn !== false) {
          syncedBreath = voice._breathCache;
        }
      } else if (voiceUsesSharedDsp(voice) && voice._sharedDspIndex >= 0) {
        voice._breathCache = null;
        voice._symmetryCrossesSlotBoundary = false;
      } else if (voice.type === 'Symmetry') {
        voice._breathCache = null;
        const slot = readSymmetrySlot(voice, elapsed);
        voice._symmetryFreqs = slot.frequencies;
        voice._symmetryEnvValue = readEnvelope(voice.symmetryEnv, slot.timeInNote);
        voice._symmetryCrossesSlotBoundary = quantumCrossesSymmetrySlotBoundary(
          voice,
          slot.timeInNote,
        );
      } else {
        voice._breathCache = null;
        voice._symmetryCrossesSlotBoundary = false;
      }
    }
    this.syncedBreathCache = syncedBreath;

    if (
      this._sharedDspVoiceIndexes.length > 0 &&
      this._sharedDspOutL &&
      this._wasmInstance?.exports?.bsc_session_render
    ) {
      this._wasmInstance.exports.bsc_session_render(QUANTUM_FRAMES, sampleRate);
      this._sharedDspRendered = true;
    }

    for (let vi = 0; vi < this.voices.length; vi += 1) {
      const voice = this.voices[vi];
      if (voice._sharedDspIndex >= 0) continue;
      if (this._wasmInstance && this._voiceOutL[vi]) {
        if (voice.type === 'Martigli-Binaural') {
          const breath = voice._breathCache;
          const fl = Math.max(20, (voice.fl ?? 250) + (voice.ma ?? 90) * breath.signed);
          const fr = Math.max(20, (voice.fr ?? 260) + (voice.ma ?? 90) * breath.signed);
          const panSwap = readPanSwap(voice, elapsed, syncedBreath);
          this._wasmInstance.exports.renderStereoQuantum(
            voice.phaseL, voice.phaseR,
            voice.waveformL ?? 0, voice.waveformR ?? 0,
            fl, fr, sampleRate, panSwap,
          );
          this._voiceOutL[vi].set(this._wasmOutL);
          this._voiceOutR[vi].set(this._wasmOutR);
          voice.phaseL = this._wasmPhase[0];
          voice.phaseR = this._wasmPhase[1];
          voice._wasmRendered = true;
        } else if (voice.type === 'Martigli') {
          const breath = voice._breathCache;
          const hz = Math.max(20, (voice.mf0 ?? 250) + (voice.ma ?? 90) * breath.signed);
          this._wasmInstance.exports.renderMartigliQuantum(
            voice.phaseM, voice.waveformM ?? voice.waveform ?? 0, hz, sampleRate,
          );
          this._voiceOutL[vi].set(this._wasmOutL);
          this._voiceOutR[vi].set(this._wasmOutR);
          voice.phaseM = this._wasmPhase[0];
          voice._wasmRendered = true;
        } else if (voice.type === 'Symmetry') {
          const freqs = voice._symmetryFreqs ?? [];
          const phaseCount = voice.symmetryPhases.length;
          const freqCount = freqs.length;
          if (
            freqCount > 0 &&
            freqCount <= 32 &&
            phaseCount <= 32 &&
            !voice._symmetryCrossesSlotBoundary
          ) {
            // Compute envelope at block start and block end for linear interpolation,
            // preserving the per-sample envelope smoothness introduced in Slice 5.
            const slot = readSymmetrySlot(voice, elapsed);
            const envStart = readEnvelope(voice.symmetryEnv, slot.timeInNote);
            const envEnd = readEnvelope(
              voice.symmetryEnv, slot.timeInNote + QUANTUM_FRAMES / sampleRate,
            );
            const envStep = (envEnd - envStart) / QUANTUM_FRAMES;
            for (let pi = 0; pi < phaseCount; pi += 1) {
              this._wasmSymmetryPhases[pi] = voice.symmetryPhases[pi];
            }
            for (let fi = 0; fi < freqCount; fi += 1) {
              this._wasmSymmetryFreqs[fi] = freqs[fi];
            }
            this._wasmInstance.exports.renderSymmetryQuantum(
              phaseCount, freqCount, envStart, envStep, voice.waveform ?? 0, sampleRate,
            );
            this._voiceOutL[vi].set(this._wasmOutL);
            this._voiceOutR[vi].set(this._wasmOutR);
            for (let pi = 0; pi < phaseCount; pi += 1) {
              voice.symmetryPhases[pi] = this._wasmSymmetryPhases[pi];
            }
            voice._wasmRendered = true;
          }
        }
      }
    }
  }

  readNoiseColor(voice, color) {
    const white = Math.random() * 2 - 1;
    if (color === 1 || voice.noiseType === 'pink') {
      const b = voice.noisePink;
      b[0] = 0.99886 * b[0] + white * 0.0555179;
      b[1] = 0.99332 * b[1] + white * 0.0750759;
      b[2] = 0.969 * b[2] + white * 0.153852;
      b[3] = 0.8665 * b[3] + white * 0.3104856;
      b[4] = 0.55 * b[4] + white * 0.5329522;
      b[5] = -0.7616 * b[5] - white * 0.016898;
      const pink = b[0] + b[1] + b[2] + b[3] + b[4] + b[5] + b[6] + white * 0.5362;
      b[6] = white * 0.115926;
      return pink * 0.11;
    }
    if (color === 2 || voice.noiseType === 'brown') {
      voice.noiseBrown = (voice.noiseBrown + 0.02 * white) / 1.02;
      return voice.noiseBrown * 3.5;
    }
    return white * 0.35;
  }

  readNoise(voice) {
    if (voice.noiseCrossfadeFramesLeft > 0) {
      const oldSample = this.readNoiseColor(voice, voice.noiseSourceColor ?? 0);
      const newSample = this.readNoiseColor(voice, voice.noiseTargetColor ?? 0);
      const total = Math.max(1, voice.noiseCrossfadeTotalFrames);
      const progress = 1 - voice.noiseCrossfadeFramesLeft / total;
      voice.noiseCrossfadeFramesLeft -= 1;
      if (voice.noiseCrossfadeFramesLeft <= 0) {
        voice.noiseColor = voice.noiseTargetColor ?? voice.noiseColor;
        voice.noiseSourceColor = voice.noiseColor;
      }
      return oldSample * (1 - progress) + newSample * progress;
    }
    return this.readNoiseColor(voice, voice.noiseColor ?? 0);
  }

  renderVoice(voice, elapsed) {
    if (voice.isOn === false || voice.currentGain <= SILENCE_GAIN) {
      this._scrL = 0;
      this._scrR = 0;
      return;
    }

    if (voice.type === 'Binaural') {
      const left = this.wave(voice.phaseL, voice.waveformL ?? 0);
      const right = this.wave(voice.phaseR, voice.waveformR ?? 0);
      voice.phaseL = wrap01(voice.phaseL + Math.max(0, voice.fl ?? 200) / sampleRate);
      voice.phaseR = wrap01(voice.phaseR + Math.max(0, voice.fr ?? 210) / sampleRate);
      const swap = readPanSwap(voice, elapsed, this.syncedBreathCache);
      if (swap !== 0) {
        this._scrL = left * (1 - swap) + right * swap;
        this._scrR = right * (1 - swap) + left * swap;
      } else {
        this._scrL = left;
        this._scrR = right;
      }
      return;
    }

    if (voice.type === 'Martigli') {
      const breath = voice._breathCache;
      const hz = Math.max(20, (voice.mf0 ?? 250) + (voice.ma ?? 90) * breath.signed);
      const sample = this.wave(voice.phaseM, voice.waveformM ?? voice.waveform ?? 0);
      voice.phaseM = wrap01(voice.phaseM + hz / sampleRate);
      this._scrL = sample * CENTER_GAIN;
      this._scrR = sample * CENTER_GAIN;
      return;
    }

    if (voice.type === 'Martigli-Binaural') {
      const breath = voice._breathCache;
      const leftHz = Math.max(20, (voice.fl ?? 250) + (voice.ma ?? 90) * breath.signed);
      const rightHz = Math.max(20, (voice.fr ?? 260) + (voice.ma ?? 90) * breath.signed);
      const left = this.wave(voice.phaseL, voice.waveformL ?? 0);
      const right = this.wave(voice.phaseR, voice.waveformR ?? 0);
      voice.phaseL = wrap01(voice.phaseL + leftHz / sampleRate);
      voice.phaseR = wrap01(voice.phaseR + rightHz / sampleRate);
      const swap = readPanSwap(voice, elapsed, this.syncedBreathCache);
      if (swap !== 0) {
        this._scrL = left * (1 - swap) + right * swap;
        this._scrR = right * (1 - swap) + left * swap;
      } else {
        this._scrL = left;
        this._scrR = right;
      }
      return;
    }

    if (voice.type === 'Symmetry') {
      const slot = readSymmetrySlot(voice, elapsed);
      const freqs = slot.frequencies;
      if (freqs.length === 0) {
        this._scrL = 0;
        this._scrR = 0;
        return;
      }
      const env = readEnvelope(voice.symmetryEnv, slot.timeInNote);
      if (env <= 0) {
        this._scrL = 0;
        this._scrR = 0;
        return;
      }
      let mono = 0;
      const laneLevel = 1 / freqs.length;
      for (let fi = 0; fi < freqs.length; fi += 1) {
        const lane = fi % voice.symmetryPhases.length;
        mono += this.wave(voice.symmetryPhases[lane], voice.waveform ?? 0) * laneLevel;
        voice.symmetryPhases[lane] = wrap01(
          voice.symmetryPhases[lane] + Math.max(20, freqs[fi]) / sampleRate,
        );
      }
      this._scrL = mono * env * CENTER_GAIN;
      this._scrR = mono * env * CENTER_GAIN;
      return;
    }

    if (voice.type === 'Noise') {
      const sample = this.readNoise(voice);
      this._scrL = sample * CENTER_GAIN;
      this._scrR = sample * CENTER_GAIN;
      return;
    }

    this._scrL = 0;
    this._scrR = 0;
  }

  reportHealth() {
    this.port.postMessage({
      type: 'health',
      renderBudgetPct: this.renderBudgetEma,
      renderBudgetMaxPct: this.renderBudgetMaxPct,
      possibleXruns: this.possibleXrunCount,
      processCalls: this.processCallCount,
      quantumMs: this.quantumDurationMs,
      wasmReady: this.wasmReady,
    });
    this.renderBudgetMaxPct = 0;
  }

  reportElapsed() {
    this.port.postMessage({
      type: 'elapsed',
      elapsed: this.elapsed,
      audioTime: currentTime,
      state: this.state,
    });
  }

  process(_inputs, outputs) {
    const renderStartPerfMs = readPerfNow();
    if (hasPerfNow && this.lastProcessEndPerfMs > 0) {
      const gap = renderStartPerfMs - this.lastProcessEndPerfMs;
      if (gap > this.quantumDurationMs * XRUN_GAP_FACTOR) {
        this.possibleXrunCount += 1;
      }
    }

    const output = outputs[0];
    const left = output[0];
    const right = output[1] ?? output[0];
    const active =
      this.state === 'playing' ||
      this.state === 'pausing' ||
      this.state === 'stopping';

    if (active) {
      this.prepareQuantum();
    }

    try {
      for (let frame = 0; frame < left.length; frame += 1) {
        let outL = 0;
        let outR = 0;

        if (active) {
          if (this._sharedDspRendered) {
            outL += this._sharedDspOutL[frame];
            outR += this._sharedDspOutR[frame];
          }

          for (let vi = 0; vi < this.voices.length; vi += 1) {
            const voice = this.voices[vi];
            if (voice._sharedDspIndex >= 0) continue;
            updateGain(voice);
            if (voice._wasmRendered) {
              outL += this._voiceOutL[vi][frame] * voice.currentGain;
              outR += this._voiceOutR[vi][frame] * voice.currentGain;
            } else {
              this.renderVoice(voice, this.elapsed);
              outL += this._scrL * voice.currentGain;
              outR += this._scrR * voice.currentGain;
            }
          }

          this.elapsed += 1 / sampleRate;
          if (this.state === 'pausing' && this.pauseFramesLeft > 0) {
            this.pauseFramesLeft -= 1;
            if (this.pauseFramesLeft <= 0) this.state = 'paused';
          } else if (this.state === 'stopping' && this.stopFramesLeft > 0) {
            this.stopFramesLeft -= 1;
            if (this.stopFramesLeft <= 0) this.state = 'stopped';
          }
        }

        left[frame] = clamp(outL, -1, 1);
        right[frame] = clamp(outR, -1, 1);
        this.framesSinceSnapshot += 1;

        if (this.framesSinceSnapshot >= FRAME_SNAPSHOT_INTERVAL) {
          this.framesSinceSnapshot = 0;
          for (let vi = 0; vi < this.voices.length; vi += 1) {
            if (this.voices[vi]._breathCache !== null) {
              this.port.postMessage({
                type: 'breathingSnapshot',
                index: vi,
                snapshot: { ...this.voices[vi]._breathCache, audioTime: currentTime },
              });
            }
          }
        }
      }
    } catch (error) {
      if (!this.fatalError) {
        this.fatalError = {
          stage: 'render',
          message: error instanceof Error ? error.message : String(error),
        };
        this.port.postMessage({ type: 'error', ...this.fatalError });
      }
    }

    this.processCallCount += 1;

    if (hasPerfNow) {
      const renderEndPerfMs = readPerfNow();
      const renderMs = renderEndPerfMs - renderStartPerfMs;
      const budgetPct = (renderMs / this.quantumDurationMs) * 100;
      this.renderBudgetEma =
        this.renderBudgetEma === 0
          ? budgetPct
          : this.renderBudgetEma * (1 - RENDER_BUDGET_EMA_ALPHA) +
            budgetPct * RENDER_BUDGET_EMA_ALPHA;
      if (budgetPct > this.renderBudgetMaxPct) {
        this.renderBudgetMaxPct = budgetPct;
      }
      this.lastProcessEndPerfMs = renderEndPerfMs;
    }

    if (active) {
      if (
        currentTime - this.lastHealthReportAudioTime >=
        HEALTH_REPORT_INTERVAL_SECONDS
      ) {
        this.lastHealthReportAudioTime = currentTime;
        this.reportHealth();
      }
      if (
        currentTime - this.lastElapsedReportAudioTime >=
        HEALTH_REPORT_INTERVAL_SECONDS
      ) {
        this.lastElapsedReportAudioTime = currentTime;
        this.reportElapsed();
      }
    }

    return true;
  }
}

registerProcessor('${WORKLET_WASM_PROCESSOR_NAME}', BscWorkletWasmSessionProcessor);
`;
}
